import {
  type CSSProperties,
  Fragment,
  type JSX,
  type KeyboardEvent,
  useCallback,
  useRef,
} from 'react';
import { useTranslation } from 'react-i18next';
import { Icons, ICON_SIZE } from '@bim-ai/ui';
import {
  isToolDisabled,
  MODIFY_TOOL_IDS,
  paletteForMode,
  type ToolDisabledContext,
  type ToolId,
  type WorkspaceMode,
} from './toolRegistry';

/**
 * ToolPalette — spec §16.
 *
 * Top-floating, mode-aware tool group. Each button is 36 × 36 with the
 * lucide icon centered and the hotkey letter as a `--text-xs` superscript
 * bottom-right. `role="toolbar"` with arrow-key traversal between
 * buttons. Active tool gets `--color-accent` background; disabled tools
 * get 0.4 opacity and the disablement reason as the tooltip.
 *
 * The Tag subdropdown (`Tag ▾`) is exposed as a separate trailing
 * button; clicking it dispatches `onTagSubmenu()` so the consumer can
 * mount the §16.5 menu.
 */

export interface ToolPaletteProps {
  mode: WorkspaceMode;
  activeTool: ToolId;
  onToolSelect: (id: ToolId) => void;
  /** Tool-disablement context (wall / floor / selection presence). */
  disabledContext: ToolDisabledContext;
  /** Tag dropdown trigger; the menu itself is rendered by the parent. */
  onTagSubmenu?: () => void;
}

export function ToolPalette({
  mode,
  activeTool,
  onToolSelect,
  disabledContext,
  onTagSubmenu,
}: ToolPaletteProps): JSX.Element {
  const { t } = useTranslation();
  const tools = paletteForMode(mode, t);
  const refs = useRef<Map<ToolId, HTMLButtonElement>>(new Map());
  const setRef = useCallback(
    (id: ToolId) => (el: HTMLButtonElement | null) => {
      if (el) refs.current.set(id, el);
      else refs.current.delete(id);
    },
    [],
  );

  const handleKey = useCallback(
    (event: KeyboardEvent<HTMLDivElement>) => {
      if (event.key !== 'ArrowRight' && event.key !== 'ArrowLeft') return;
      const idx = tools.findIndex((t) => t.id === activeTool);
      if (idx < 0) return;
      const delta = event.key === 'ArrowRight' ? 1 : -1;
      const next = tools[(idx + delta + tools.length) % tools.length]!;
      event.preventDefault();
      onToolSelect(next.id);
      refs.current.get(next.id)?.focus();
    },
    [activeTool, onToolSelect, tools],
  );

  return (
    <div
      role="toolbar"
      aria-label="Drawing tools"
      data-testid="tool-palette"
      onKeyDown={handleKey}
      style={paletteStyle}
      className="flex items-center gap-0.5 rounded-md border border-border bg-background/95 px-1.5 py-1.5 shadow-elev-2 backdrop-blur-sm"
    >
      {tools.map((tool, idx) => {
        const Icon = Icons[tool.icon]!;
        const enablement = isToolDisabled(tool.id, disabledContext, t);
        const isActive = tool.id === activeTool;
        const isFirstModify =
          MODIFY_TOOL_IDS.has(tool.id) && (idx === 0 || !MODIFY_TOOL_IDS.has(tools[idx - 1]!.id));
        return (
          <Fragment key={tool.id}>
            {isFirstModify && (
              <div aria-hidden="true" className="mx-0.5 h-5 w-px self-center bg-border" />
            )}
            <button
              ref={setRef(tool.id)}
              type="button"
              aria-label={`${tool.label} (${tool.hotkey})`}
              aria-pressed={isActive}
              aria-keyshortcuts={tool.hotkey}
              aria-disabled={enablement.disabled}
              tabIndex={isActive ? 0 : -1}
              disabled={enablement.disabled}
              title={enablement.disabled ? enablement.reason : tool.tooltip}
              data-tool={tool.id}
              data-active={isActive ? 'true' : 'false'}
              onClick={() => {
                if (enablement.disabled) return;
                if (tool.id === 'tag') onTagSubmenu?.();
                else onToolSelect(tool.id);
              }}
              className={[
                'relative inline-flex h-8 w-8 items-center justify-center rounded transition-colors',
                isActive
                  ? 'bg-accent text-accent-foreground shadow-sm'
                  : 'text-muted hover:bg-surface hover:text-foreground',
                enablement.disabled ? 'opacity-40' : '',
              ].join(' ')}
            >
              <Icon size={16} aria-hidden="true" />
              <span
                aria-hidden="true"
                className="pointer-events-none absolute bottom-0.5 right-0.5 text-[8px] font-medium opacity-60 tabular-nums"
              >
                {tool.hotkey.replace('Shift+', '⇧')}
              </span>
            </button>
          </Fragment>
        );
      })}
    </div>
  );
}

const paletteStyle: CSSProperties = {
  // Top-center floating per §16; absolute positioning is left to caller.
  zIndex: 10,
};

import { type JSX, useEffect, useRef, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { ICON_SIZE, Icons, type LucideLikeIcon } from '@bim-ai/ui';

import { TAB_KIND_LABEL, type TabKind, type ViewTab } from './tabsModel';

/**
 * TabBar — spec §11.3.
 *
 * Horizontal strip of open-view tabs sitting between the TopBar and
 * the canvas. Each tab carries a `kind` icon, a truncated label, and a
 * close ✕ button. Trailing `+` opens an "add view" popover.
 */

const TAB_KIND_ICON: Record<TabKind, LucideLikeIcon> = {
  plan: Icons.floor!,
  '3d': Icons.family!, // Component (cube) — used for 3D views
  'plan-3d': Icons.floor!,
  section: Icons.section!,
  sheet: Icons.sheet!,
  schedule: Icons.schedule!,
  agent: Icons.agent!,
};

export interface TabBarProps {
  tabs: ViewTab[];
  activeId: string | null;
  onActivate: (id: string) => void;
  onClose: (id: string) => void;
  /** Called when the user clicks a "+ {kind}" entry in the trailing
   * popover. The kind names a target the host should resolve (e.g.
   * "+ Plan" → open the active level as a tab). */
  onAdd?: (kind: TabKind) => void;
  /** Called when the user drags a tab to a new position. The host
   * should run the `reorderTab` reducer with the same indices. */
  onReorder?: (fromIdx: number, toIdx: number) => void;
}

const ADDABLE_KINDS: TabKind[] = ['plan', '3d', 'plan-3d', 'section', 'sheet', 'schedule', 'agent'];

export function TabBar({
  tabs,
  activeId,
  onActivate,
  onClose,
  onAdd,
  onReorder,
}: TabBarProps): JSX.Element {
  const { t } = useTranslation();
  const [popoverOpen, setPopoverOpen] = useState(false);
  const [dragSrc, setDragSrc] = useState<number | null>(null);
  const [dragOverIdx, setDragOverIdx] = useState<number | null>(null);
  const popoverRef = useRef<HTMLDivElement | null>(null);

  // Click-outside closes the popover.
  useEffect(() => {
    if (!popoverOpen) return;
    const onDoc = (e: MouseEvent): void => {
      if (popoverRef.current && !popoverRef.current.contains(e.target as Node)) {
        setPopoverOpen(false);
      }
    };
    document.addEventListener('mousedown', onDoc);
    return () => document.removeEventListener('mousedown', onDoc);
  }, [popoverOpen]);

  return (
    <div
      role="tablist"
      aria-label={t('workspace.openViews')}
      data-testid="view-tabs"
      className="flex items-end gap-0.5 border-b border-border bg-surface px-2 pt-1.5"
      style={{ height: 38 }}
    >
      {tabs.length === 0 ? (
        <div className="px-2 pb-1.5 text-xs text-muted">{t('workspace.noViewsOpen')}</div>
      ) : null}
      {tabs.map((tab, idx) => {
        const Icon = TAB_KIND_ICON[tab.kind] ?? Icons.floor!;
        const isActive = tab.id === activeId;
        const isDragOver = dragOverIdx === idx && dragSrc !== null && dragSrc !== idx;
        const truncated = tab.label.length > 22 ? tab.label.slice(0, 21) + '…' : tab.label;
        return (
          <div
            key={tab.id}
            role="tab"
            aria-selected={isActive}
            data-tab-id={tab.id}
            data-tab-index={idx}
            data-active={isActive ? 'true' : 'false'}
            data-drag-over={isDragOver ? 'true' : 'false'}
            draggable={Boolean(onReorder)}
            onDragStart={(e) => {
              if (!onReorder) return;
              setDragSrc(idx);
              e.dataTransfer.effectAllowed = 'move';
              try {
                e.dataTransfer.setData('text/plain', String(idx));
              } catch {
                /* some browsers throw on setData inside synthetic events */
              }
            }}
            onDragOver={(e) => {
              if (!onReorder || dragSrc === null) return;
              e.preventDefault();
              e.dataTransfer.dropEffect = 'move';
              if (dragOverIdx !== idx) setDragOverIdx(idx);
            }}
            onDragLeave={() => {
              if (dragOverIdx === idx) setDragOverIdx(null);
            }}
            onDrop={(e) => {
              if (!onReorder || dragSrc === null) return;
              e.preventDefault();
              if (dragSrc !== idx) onReorder(dragSrc, idx);
              setDragSrc(null);
              setDragOverIdx(null);
            }}
            onDragEnd={() => {
              setDragSrc(null);
              setDragOverIdx(null);
            }}
            className={[
              'group flex items-center gap-1.5 rounded-t-md border border-b-0 px-3 py-1.5 text-xs font-medium transition-colors',
              isActive
                ? 'border-border bg-background text-foreground shadow-sm'
                : 'border-transparent text-muted hover:bg-background/60 hover:text-foreground',
              isDragOver ? 'ring-2 ring-accent ring-offset-0' : '',
            ].join(' ')}
            style={
              isActive
                ? {
                    boxShadow:
                      'inset 0 -2px 0 0 var(--color-accent), 0 -1px 3px 0 rgba(0,0,0,0.04)',
                  }
                : undefined
            }
          >
            <button
              type="button"
              onClick={() => onActivate(tab.id)}
              aria-label={`${t(`workspace.tabs.${tab.kind}`)}: ${tab.label}`}
              className="flex items-center gap-1.5 rounded"
              title={`${t(`workspace.tabs.${tab.kind}`)} · ${tab.label}`}
              data-testid={`tab-activate-${tab.id}`}
            >
              <Icon
                size={13}
                aria-hidden="true"
                className={isActive ? 'text-accent' : 'text-muted'}
              />
              <span className="whitespace-nowrap">{truncated}</span>
            </button>
            <button
              type="button"
              onClick={(e) => {
                e.stopPropagation();
                onClose(tab.id);
              }}
              aria-label={t('workspace.closeTab', { label: tab.label })}
              data-testid={`tab-close-${tab.id}`}
              className={[
                'rounded p-0.5 hover:bg-surface-strong',
                isActive
                  ? 'opacity-50 hover:opacity-100'
                  : 'opacity-0 group-hover:opacity-50 group-hover:hover:opacity-100',
              ].join(' ')}
            >
              <Icons.close size={11} aria-hidden="true" />
            </button>
          </div>
        );
      })}
      <div className="relative ml-1 mb-1.5" ref={popoverRef}>
        <button
          type="button"
          onClick={() => setPopoverOpen((v) => !v)}
          aria-label={t('workspace.openNewView')}
          data-testid="tab-add-button"
          className="flex h-6 w-6 items-center justify-center rounded text-muted hover:bg-surface-strong hover:text-foreground"
          style={{ fontSize: 16, lineHeight: 1 }}
        >
          +
        </button>
        {popoverOpen ? (
          <div
            role="menu"
            data-testid="tab-add-popover"
            className="absolute left-0 top-full z-30 mt-1 flex min-w-[180px] flex-col rounded-md border border-border bg-surface shadow-elev-2"
          >
            {ADDABLE_KINDS.map((kind) => {
              const Icon = TAB_KIND_ICON[kind];
              return (
                <button
                  key={kind}
                  type="button"
                  role="menuitem"
                  onClick={() => {
                    setPopoverOpen(false);
                    onAdd?.(kind);
                  }}
                  className="flex items-center gap-2 px-3 py-1.5 text-left text-xs text-foreground hover:bg-surface-strong"
                  data-testid={`tab-add-${kind}`}
                >
                  <Icon size={ICON_SIZE.chrome} aria-hidden="true" />
                  <span>+ {t(`workspace.tabs.${kind}`)}</span>
                </button>
              );
            })}
          </div>
        ) : null}
      </div>
    </div>
  );
}

import type { Element } from '@bim-ai/core';

import type { ScheduleFieldMeta } from './schedulePanelRegistryChrome';
import { scheduleTotalsReadoutParts } from './schedulePayloadTotals';

export const SCHEDULE_TABLE_EMPTY_V1 = 'schedule_table_empty_v1';

export type ScheduleTableColumnV1 = {
  key: string;
  headerLabel: string;
  unitLabel: string;
  roleLabel: string;
  displayWidthHintPx: number;
};

export type ScheduleTableBodyRowV1 =
  | { id: string; kind: 'groupHeader'; label: string }
  | { id: string; kind: 'data'; record: Record<string, unknown> };

export type ScheduleTableModelV1 = {
  title: string;
  columns: ScheduleTableColumnV1[];
  bodyRows: ScheduleTableBodyRowV1[];
  leafRowCount: number;
  groupCount: number;
  emptyToken: string | null;
  footerParts: string[];
};

const SCH_DOC_OK = /^schDoc\[id=([^[\]]+) rows=(\d+) cols=(\d+) cat=([^[\]]+)\]$/;

/** Extract a trailing parenthetical unit snippet from registry labels, e.g. "(mm)", "(m²)". */
export function unitHintFromRegistryLabel(label: string): string {
  const m = /\(([^)]+)\)\s*$/.exec(label.trim());
  return m?.[1]?.trim() ?? '';
}

function roleWidthHintPx(role: string | undefined): number {
  const r = (role ?? '').toLowerCase();
  switch (r) {
    case 'id':
      return 72;
    case 'identity':
      return 88;
    case 'integer':
      return 92;
    case 'number':
      return 96;
    case 'text':
      return 140;
    default:
      return 110;
  }
}

export function columnDisplayWidthHintPx(
  fieldKey: string,
  meta: ScheduleFieldMeta | undefined,
): number {
  const k = fieldKey.toLowerCase();
  if (k === 'elementid' || k.endsWith('elementid')) return 72;
  if (k.includes('display') || k === 'name' || k.includes('name'))
    return Math.max(roleWidthHintPx(meta?.role), 128);
  return roleWidthHintPx(meta?.role);
}

function orderedColumnKeys(
  payload: Record<string, unknown>,
  visibleColumnKeys: string[] | undefined,
): string[] {
  const all = Array.isArray(payload.columns) ? (payload.columns as string[]) : [];
  if (!visibleColumnKeys?.length) return all;
  const want = new Set(visibleColumnKeys);
  return visibleColumnKeys.filter((c) => all.includes(c));
}

function fieldMetaMap(payload: Record<string, unknown>): Record<string, ScheduleFieldMeta> {
  const raw = payload.columnMetadata as { fields?: Record<string, ScheduleFieldMeta> } | undefined;
  const fields = raw?.fields ?? {};
  return fields as Record<string, ScheduleFieldMeta>;
}

function leafRowsFromPayload(payload: Record<string, unknown>): Record<string, unknown>[] {
  const rows = payload.rows;
  if (Array.isArray(rows)) return rows as Record<string, unknown>[];

  const gs = payload.groupedSections as Record<string, unknown[]> | undefined;
  if (gs && typeof gs === 'object') {
    const out: Record<string, unknown>[] = [];
    for (const v of Object.values(gs)) {
      if (Array.isArray(v)) out.push(...(v as Record<string, unknown>[]));
    }
    return out;
  }

  return [];
}

function buildBodyRows(payload: Record<string, unknown>): {
  bodyRows: ScheduleTableBodyRowV1[];
  leafRowCount: number;
  groupCount: number;
} {
  const gs = payload.groupedSections as Record<string, Record<string, unknown>[]> | undefined;

  if (gs && typeof gs === 'object' && !Array.isArray(gs)) {
    const keys = Object.keys(gs).sort((a, b) => a.localeCompare(b));
    const nonempty = keys.filter((k) => {
      const v = gs[k];
      return Array.isArray(v) && v.length > 0;
    });
    if (nonempty.length > 0 || keys.some((k) => Array.isArray(gs[k]))) {
      const bodyRows: ScheduleTableBodyRowV1[] = [];
      let leaf = 0;
      let gix = 0;
      for (const k of keys) {
        const prow = gs[k];
        const arr = Array.isArray(prow) ? prow : [];
        bodyRows.push({
          id: `grp-${gix}-${encodeURIComponent(k)}`,
          kind: 'groupHeader',
          label: k,
        });
        gix += 1;
        arr.forEach((r, i) => {
          const rec = r as Record<string, unknown>;
          bodyRows.push({
            id: String(rec.elementId ?? rec.element_id ?? `row-${k}-${i}`),
            kind: 'data',
            record: rec,
          });
          leaf += 1;
        });
      }
      return { bodyRows, leafRowCount: leaf, groupCount: keys.length };
    }
  }

  const flat = Array.isArray(payload.rows)
    ? (payload.rows as Record<string, unknown>[])
    : leafRowsFromPayload(payload);
  const bodyRows: ScheduleTableBodyRowV1[] = flat.map((r, i) => ({
    id: String(r.elementId ?? (r as { element_id?: string }).element_id ?? `row-${i}`),
    kind: 'data' as const,
    record: r,
  }));

  return { bodyRows, leafRowCount: bodyRows.length, groupCount: 0 };
}

export function buildScheduleTableModelV1(options: {
  payload: Record<string, unknown>;
  visibleColumnKeys?: string[];
}): ScheduleTableModelV1 {
  const { payload, visibleColumnKeys } = options;

  const keys = orderedColumnKeys(payload, visibleColumnKeys);
  const fmeta = fieldMetaMap(payload);

  const columns: ScheduleTableColumnV1[] = keys.map((key) => {
    const meta = fmeta[key];
    const headerLabel = meta?.label?.trim() ? meta.label.trim() : key;
    const unitLabel = unitHintFromRegistryLabel(headerLabel);
    const roleLabel = typeof meta?.role === 'string' ? meta.role.trim() : '';
    return {
      key,
      headerLabel,
      unitLabel,
      roleLabel,
      displayWidthHintPx: columnDisplayWidthHintPx(key, meta),
    };
  });

  let title = String(payload.name ?? '').trim();
  if (!title) {
    const sid = String(payload.scheduleId ?? payload.schedule_id ?? '').trim();
    title = sid ? `Schedule (${sid})` : 'Schedule';
  }

  const rawTotals = payload.totals as Record<string, unknown> | undefined;
  const footerParts = scheduleTotalsReadoutParts(rawTotals);

  const { bodyRows, leafRowCount, groupCount } = buildBodyRows(payload);

  const emptyToken = leafRowCount === 0 ? SCHEDULE_TABLE_EMPTY_V1 : null;

  return {
    title,
    columns,
    bodyRows,
    leafRowCount,
    groupCount,
    emptyToken,
    footerParts,
  };
}

export function formatScheduleTableRendererV1Readout(model: ScheduleTableModelV1): string {
  const footer = model.footerParts.length > 0 ? 'yes' : 'no';
  return `tblV1[cols=${model.columns.length} leafRows=${model.leafRowCount} groups=${model.groupCount} footer=${footer}]`;
}

/**
 * Narrow sheet-documentation readout: enrich deterministic `schDoc[…]` summary with schedule name when resolvable.
 */
export function scheduleTableRendererV1SheetReadout(
  scheduleDocumentationSegment: string,
  elementsById: Record<string, Element>,
): string | null {
  const seg = String(scheduleDocumentationSegment ?? '').trim();
  const m = SCH_DOC_OK.exec(seg);
  if (!m) return null;

  const [, idRaw, rowsStr, colsStr, catRaw] = m;
  const el = elementsById[idRaw];
  const name =
    el?.kind === 'schedule'
      ? String(el.name ?? '')
          .trim()
          .replace(/\]/g, '')
          .replace(/\[/g, '')
      : '';

  const safeName = name ? ` name=${name}` : '';
  return `tblV1[id=${idRaw}${safeName} rows=${rowsStr} cols=${colsStr} cat=${catRaw}]`;
}

