import { expect, test } from '@playwright/test';

/**
 * UI redesign visual regression baselines — spec §28 last row + §11–§17.
 *
 * One screenshot per redesigned chrome surface. The /redesign route
 * mounts the composed shell (TopBar / LeftRail / Inspector / StatusBar
 * / ToolPalette + Plan / Viewport canvas) so these snapshots cover the
 * §11–§17 surfaces in one go.
 *
 * Run with `pnpm exec playwright test --update-snapshots` from
 * `packages/web/` to (re)generate baselines locally.
 */

const VIEWPORT = { width: 1440, height: 900 };

test.describe('UI redesign — chrome baselines', () => {
  test.use({ viewport: VIEWPORT });

  test.beforeEach(async ({ page }) => {
    await page.goto('/');
    await page.waitForSelector('[data-testid="app-shell"]');
  });

  test('app-shell light @ 1440 × 900', async ({ page }) => {
    await page.evaluate(() => {
      document.documentElement.setAttribute('data-theme', 'light');
    });
    await expect(page).toHaveScreenshot('app-shell-light.png', {
      fullPage: false,
      maxDiffPixelRatio: 0.07,
    });
  });

  test('app-shell dark @ 1440 × 900', async ({ page }) => {
    await page.evaluate(() => {
      document.documentElement.setAttribute('data-theme', 'dark');
    });
    await expect(page).toHaveScreenshot('app-shell-dark.png', {
      fullPage: false,
      maxDiffPixelRatio: 0.07,
    });
  });

  test('top-bar mode pills', async ({ page }) => {
    const topbar = page.getByTestId('topbar');
    await expect(topbar).toBeVisible();
    await expect(topbar).toHaveScreenshot('top-bar.png', {
      maxDiffPixelRatio: 0.05,
    });
  });

  test('left-rail Project Browser', async ({ page }) => {
    const rail = page.getByTestId('app-shell-left-rail');
    await expect(rail).toBeVisible();
    await expect(rail).toHaveScreenshot('left-rail.png', {
      maxDiffPixelRatio: 0.05,
    });
  });

  test('right-rail Inspector empty state', async ({ page }) => {
    const rail = page.getByTestId('inspector');
    await expect(rail).toBeVisible();
    await expect(rail).toHaveScreenshot('right-rail-empty.png', {
      maxDiffPixelRatio: 0.05,
    });
  });

  test('status-bar clusters', async ({ page }) => {
    const bar = page.getByTestId('status-bar');
    await expect(bar).toBeVisible();
    await expect(bar).toHaveScreenshot('status-bar.png', {
      maxDiffPixelRatio: 0.05,
    });
  });

  test('tool-palette plan mode', async ({ page }) => {
    const palette = page.getByTestId('tool-palette');
    await expect(palette).toBeVisible();
    await expect(palette).toHaveScreenshot('tool-palette.png', {
      maxDiffPixelRatio: 0.05,
    });
  });
});

import { defineConfig } from '@playwright/test';

/** Browser smoke runs against Vite preview; API is mocked via `page.route`. */
export default defineConfig({
  testDir: './e2e',
  timeout: 60_000,
  forbidOnly: Boolean(process.env.CI),
  snapshotPathTemplate: '{testDir}/__screenshots__/{testFilePath}/{platform}/{arg}{ext}',
  reporter: [['list'], ['html', { open: 'never', outputFolder: 'playwright-report' }]],
  outputDir: 'test-results',
  expect: {
    toHaveScreenshot: {
      animations: 'disabled',
      maxDiffPixelRatio: 0.068,
      threshold: 0.28,
    },
  },
  use: {
    baseURL: 'http://127.0.0.1:5739',
  },
  webServer: {
    /** CI `pnpm verify` may leave `dist/` without E2E flags; always rebuild for Playwright. */

    command:
      'rm -rf dist && env PREVIEW_NO_PROXY=1 VITE_E2E_DISABLE_WS=true pnpm exec vite build && env PREVIEW_NO_PROXY=1 pnpm exec vite preview --host 127.0.0.1 --strictPort --port 5739',
    env: {
      PREVIEW_NO_PROXY: '1',
      VITE_E2E_DISABLE_WS: 'true',
    },
    url: 'http://127.0.0.1:5739',
    reuseExistingServer: process.env.CI !== 'true',
    timeout: 180_000,
  },
});

import { createHash } from 'node:crypto';

import { expect, test, type Page } from '@playwright/test';

/** Visual baselines for Revit-parity Phase A evidence (sheet + schedules + split plan / 3D regions). */

const MODEL_ID = '00000000-0000-4000-a000-00000000e2e';

/** Mock evidence-package semantic tokens (stable; aligns with deterministicSheetEvidence[].playwright PNG stem). */

const MOCK_SEMANTIC_DIGEST_SHA256 =
  'e2efe2e0e2efe2e000000000000000000000000000000000000000000000000';

const MOCK_SEMANTIC_PREFIX16 = MOCK_SEMANTIC_DIGEST_SHA256.slice(0, 16);

const MOCK_EVIDENCE_BASENAME = `bim-ai-evidence-${MOCK_SEMANTIC_PREFIX16}-r3`;

/** Expected Playwright PNG filename for GA-01 sheet canvas (deterministicSheetEvidence stub). */

const MOCK_SHEET_VIEWPORT_PNG_FROM_MANIFEST = `${MOCK_EVIDENCE_BASENAME}-sheet-hf-sheet-ga01-viewport.png`;

const MOCK_SHEET_FULL_PNG_FROM_MANIFEST = `${MOCK_EVIDENCE_BASENAME}-sheet-hf-sheet-ga01-full.png`;

const MOCK_SHEET_RASTER_PLACEHOLDER_PROBE = `${MOCK_EVIDENCE_BASENAME}-sheet-hf-sheet-ga01.raster-placeholder.png`;

/** Print-surrogate v2 PNG bytes for mocked `sheet-print-raster` (matches server `sheetPrintRasterPrintSurrogate_v2`). */
const MOCK_SHEET_PRINT_RASTER_PNG_B64 =
  '';

const MOCK_SHEET_PRINT_RASTER_PNG_BYTES = Uint8Array.from(
  Buffer.from(MOCK_SHEET_PRINT_RASTER_PNG_B64, 'base64'),
);

/** Sorted like server `evidenceClosureReview_v1.expectedDeterministicPngBasenames` for mock + assertions. */
const MOCK_CLOSURE_DETERMINISTIC_PNG_BASENAMES = [
  `${MOCK_EVIDENCE_BASENAME}-plan-pv-eg.png`,
  `${MOCK_EVIDENCE_BASENAME}-section-hf-sec-demo.png`,
  MOCK_SHEET_FULL_PNG_FROM_MANIFEST,
  MOCK_SHEET_VIEWPORT_PNG_FROM_MANIFEST,
].sort();

/** Canonical ingest pairs (sorted like `artifact_ingest_correlation_v1` in `evidence_manifest.py`). */
const MOCK_INGEST_PAIRS_SORTED = MOCK_CLOSURE_DETERMINISTIC_PNG_BASENAMES.filter((bn) =>
  bn.endsWith('.png'),
)
  .map((bn) => ({
    baselinePngBasename: bn,
    expectedDiffBasename: `${bn.replace(/\.png$/, '')}-diff.png`,
  }))
  .sort(
    (a, b) =>
      a.baselinePngBasename.localeCompare(b.baselinePngBasename) ||
      a.expectedDiffBasename.localeCompare(b.expectedDiffBasename),
  );

const MOCK_ARTIFACT_INGEST_DIGEST = createHash('sha256')
  .update(JSON.stringify(MOCK_INGEST_PAIRS_SORTED))
  .digest('hex');

